instruction:
Two ways to create an array:

```java
// Method 1: declare with size (all zeros/null)
int[] scores = new int[5];

// Method 2: declare with values
int[] scores = {95, 87, 73, 91, 68};
```

Access with index (0-based). `.length` gives the count.

Run this.

starter:
public class Main {
    public static void main(String[] args) {
        int[] scores = {95, 87, 73, 91, 68};

        System.out.println("Length: " + scores.length);
        System.out.println("First: " + scores[0]);
        System.out.println("Last: " + scores[scores.length - 1]);

        // Modify an element:
        scores[2] = 80;
        System.out.println("Updated index 2: " + scores[2]);
    }
}

public class Main {
    public static void main(String[] args) {
        int[] scores = {95, 87, 73, 91, 68};

        // TODO: print each score with its index: "0: 95"
        for (int i = 0; i < scores.length; i++) {
            System.out.println(i + ": " + scores[i]);
        }
    }
}

public class Main {
    public static void main(String[] args) {
        int[] scores = {95, 87, 73, 91, 68, 82};

        // TODO: calculate sum, min, max
        int sum = 0;
        int min = scores[0];
        int max = scores[0];

        for (int s : scores) {
            sum += s;
            if (s < min) min = s;
            if (s > max) max = s;
        }

        System.out.println("Sum: " + sum);
        System.out.println("Min: " + min);
        System.out.println("Max: " + max);
        System.out.println("Avg: " + (double) sum / scores.length);
    }
}

import java.util.Arrays;

public class Main {
    public static void main(String[] args) {
        int[] scores = {95, 87, 73, 91, 68, 82};

        System.out.println(Arrays.toString(scores));

        Arrays.sort(scores);
        System.out.println(Arrays.toString(scores));

        int idx = Arrays.binarySearch(scores, 87);
        System.out.println("87 is at index: " + idx);

        int[] copy = Arrays.copyOf(scores, 3); // first 3 elements
        System.out.println(Arrays.toString(copy));
    }
}

public class Main {
    public static void main(String[] args) {
        int[] scores = {10, 20, 30, 40, 50};

        // BUG 1: accessing index 5 (length is 5, max index is 4)
        // System.out.println(scores[5]); // fix: scores[4] or scores[scores.length-1]

        System.out.println(scores[scores.length - 1]); // last element safely
        System.out.println(scores[0]);                  // first element
        System.out.println(scores.length);              // count
    }
}

public class Main {
    public static void main(String[] args) {
        // Identity matrix: 1s on the diagonal, 0s elsewhere
        int[][] identity = new int[3][3];
        for (int i = 0; i < 3; i++) {
            identity[i][i] = 1;
        }

        // Print it:
        for (int[] row : identity) {
            for (int val : row) {
                System.out.print(val + " ");
            }
            System.out.println();
        }
    }
}
